<details>
<summary>Script from Claude</summary>

```js
#!/usr/bin/env node

// Compares oxlint rules against upstream ESLint plugin rules to find rules
// where the upstream original has a fixer or suggestion but oxlint does not.
//
// Usage: node check-missing-fixers.mjs
//
// Prerequisites: build oxlint first (`cargo build -p oxlint`), and ensure
// dependencies are installed in tasks/lint_rules (`pnpm install`).

import { execSync } from "node:child_process";
import { createESLintLinter, loadTargetPluginRules } from "./tasks/lint_rules/src/eslint-rules.mjs";

// Scope names used by oxlint mapped to the prefix used when loading rules
// into the ESLint Linter instance (see eslint-rules.mjs).
const SCOPE_TO_PREFIX = {
  eslint: null,        // core rules have no prefix in ESLint
  typescript: "typescript",
  import: "import",
  jest: "jest",
  jsdoc: "jsdoc",
  jsx_a11y: "jsx-a11y",
  nextjs: "nextjs",
  node: "n",
  promise: "promise",
  react: "react",
  react_perf: "react-perf",
  unicorn: "unicorn",
  vitest: "vitest",
  vue: "vue",
};

// Get oxlint rules as JSON
const oxlintOutput = execSync("cargo run -p oxlint -- --rules --format=json", {
  encoding: "utf-8",
  stdio: ["pipe", "pipe", "pipe"],
});
const oxlintRules = JSON.parse(oxlintOutput);

// Load all upstream ESLint plugin rules
const linter = createESLintLinter();
loadTargetPluginRules(linter, true);
const allUpstreamRules = linter.getRules();

// Filter oxlint rules: skip those that already have a fixer/suggestion or are pending
const candidates = oxlintRules.filter((rule) => {
  // Skip oxc-specific rules (no upstream equivalent)
  if (rule.scope === "oxc") return false;
  // Skip rules that already have some kind of fix or are pending
  if (rule.fix !== "none") return false;
  return true;
});

// Separate pending rules for a separate summary
const pendingRules = oxlintRules.filter((rule) => rule.fix === "pending");

const missing = [];

for (const rule of candidates) {
  const prefix = SCOPE_TO_PREFIX[rule.scope];
  if (prefix === undefined) {
    // Unknown scope, skip
    continue;
  }

  // Build the key used in the ESLint Linter's rule map
  const linterKey = prefix ? `${prefix}/${rule.value}` : rule.value;

  let upstream = allUpstreamRules.get(linterKey);

  // Fallback: try @typescript-eslint/ prefix for typescript rules
  if (!upstream && rule.scope === "typescript") {
    upstream = allUpstreamRules.get(`@typescript-eslint/${rule.value}`);
  }

  // Broader fallback: search by rule name suffix
  if (!upstream) {
    for (const [key, r] of allUpstreamRules) {
      if (key === rule.value || key.endsWith(`/${rule.value}`)) {
        upstream = r;
        break;
      }
    }
  }

  if (!upstream || !upstream.meta) {
    continue;
  }

  const hasUpstreamFix = !!upstream.meta.fixable;
  const hasUpstreamSuggestions = !!upstream.meta.hasSuggestions;

  if (hasUpstreamFix || hasUpstreamSuggestions) {
    missing.push({
      scope: rule.scope,
      rule: rule.value,
      linterKey,
      upstreamFixable: hasUpstreamFix ? upstream.meta.fixable : false,
      upstreamHasSuggestions: hasUpstreamSuggestions,
      oxlintFix: rule.fix,
    });
  }
}

// Sort by scope, then rule name
missing.sort((a, b) => a.scope.localeCompare(b.scope) || a.rule.localeCompare(b.rule));

// Print results
if (missing.length === 0) {
  console.log("All oxlint rules with upstream fixers/suggestions are covered!");
} else {
  console.log(`Found ${missing.length} rules where upstream has fixer/suggestion but oxlint does not:\n`);

  let currentScope = null;
  for (const entry of missing) {
    if (entry.scope !== currentScope) {
      currentScope = entry.scope;
      console.log(`\n## ${currentScope}`);
    }

    const parts = [];
    if (entry.upstreamFixable) parts.push(`fixable(${entry.upstreamFixable})`);
    if (entry.upstreamHasSuggestions) parts.push("hasSuggestions");

    console.log(`  ${entry.rule} — upstream: ${parts.join(", ")}`);
  }
}

// Summary
console.log("\n--- Summary ---");
console.log(`Total oxlint rules: ${oxlintRules.length}`);
console.log(`Rules with fix/suggestion in oxlint: ${oxlintRules.filter((r) => r.fix !== "none" && r.fix !== "pending").length}`);
console.log(`Rules marked pending in oxlint: ${pendingRules.length}`);
console.log(`Rules missing upstream fixer/suggestion: ${missing.length}`);
```

