### What happened?

the react/exhaustive-deps rule has a bug that can result in an error loop where it claims a dependency is missing, but when you add it you get an error saying it's unnecessary.  here's the minimal repro:

```tsx
import { useCallback, type RefObject, useRef } from "react";

export const Upstream = () => {
  const myRef = useRef<number | null>(null);
  return <Downstream myRef={myRef} />;
};

const Downstream = ({ myRef }: { myRef: RefObject<number | null> }) => {
  const scenarioA = useCallback(() => {
    console.log(myRef.current);
  // React Hook useCallback has an unnecessary dependency: myRef.
  }, [myRef.current]);

  const scenarioB = useCallback(() => {
    console.log(myRef.current)
  // React Hook useCallback has a missing dependency: 'myRef.current'
  }, []);

  return (
    <>
      <div onClick={scenarioA} />
      <div onClick={scenarioB} />
    </>
  );
};
```

