    "env": {
        "builtin": true,
        "node": true
    },
    "rules": {
        "typescript/explicit-function-return-type": "error"
    }
}
```



### What happened?

Might be an misunderstanding on my behalf, but the `typescript/explicit-function-return-type` rule seems to regard try/catch blocks as higher order functions, so they aren't being flagged as needing an explicit return type unless `allowHigherOrderFunctions` is true.

```ts
// Missing return type on function - yay!
export function myFunction() {
    return "something";
}

// No missing returning type warning - ???
export function myFunction2() {
    try {
        return "something";
    } catch (error) {
        throw new Error("some wrapped", { cause: error });
    }
}
```

