```js
#!/usr/bin/env bun

import { rolldown } from "rolldown"
// import read from "@3-/read"
import write from "@3-/write"

const treeshake = async (input, manualPureFunctions) => {
  const {
    output: [{ code }],
  } = await (
    await rolldown({
      input,
      treeshake: {
        preset: "smallest",
        unknownGlobalSideEffects: false,
        moduleSideEffects: false,
        manualPureFunctions,
      },
    })
  ).generate({
    format: "esm",
    minify: {
      compress: {
        target: "esnext",
      },
      mangle: {
        toplevel: false,
      },
    },
  })
  // , src = read(input)
