```

### Expected Result

Expected the `name` property of each of the `defs` for bindings in the catch clause param to be the `Identifier`s for those bindings, matching ESLint's behavior.

That behavior is also consistent with TS-ESLint for other places where bindings are defined via destructuring e.g.:

```js
const { a } = foo();
const [ b ] = bar();
function f({ c }) {}
```

### Actual Result

`def.name` is the catch clause param node (`ObjectPattern` or `ArrayPattern`).

### Additional Info

A small ESLint plugin which demonstrates that ESLint has `def.name` as the `Identifier` for each binding:

```js
export default {
  rules: {
    'check-catch-scopes': {
      create(context) {
        for (const scope of context.sourceCode.scopeManager.scopes) {
          checkScope(scope);
        }

        return {};
      },
    },
  },
};

function checkScope(scope) {
  if (scope.type !== "catch") return;

  for (const variable of scope.variables) {
    const { name } = variable;
    const error = checkVar(variable);
    if (error) {
      console.log("FAIL:", name, error);
    } else {
      console.log("Pass:", name);
    }
  }
}

function checkVar(variable) {
  const { defs, identifiers } = variable;
  if (defs.length !== 1) return "More than 1 def";
  if (identifiers.length !== 1) return "More than 1 identifier";

  const defName = defs[0].name;
  if (defName.type !== "Identifier") return "Not Identifier";
  const ident = identifiers[0];
  if (defName.start !== ident.start || defName.end !== ident.end) return "Span mismatch";
}
```

Run on the above source (without TS-ESLint), it logs:

```
Pass: a
Pass: b
Pass: c
Pass: d
Pass: e
Pass: f
Pass: g
Pass: h
Pass: i
Pass: j
```

